import 'package:flutter/material.dart';
import 'package:flutter/services.dart';
import 'package:new_launcher/action.dart';
import 'package:new_launcher/data.dart';
import 'package:new_launcher/provider.dart';
import 'package:provider/provider.dart';

GitIgnoreModel gitIgnoreModel = GitIgnoreModel();

MyProvider providerGitIgnoreGenerator = MyProvider(
    name: "GitIgnore",
    provideActions: _provideActions,
    initActions: _initActions,
    update: _update);

Future<void> _provideActions() async {
  Global.addActions([
    MyAction(
      name: 'GitIgnore Generator',
      keywords: 'gitignore git ignore template generate language framework',
      action: () => gitIgnoreModel.refresh(),
      times: List.generate(24, (index) => 0),
    ),
  ]);
}

Future<void> _initActions() async {
  gitIgnoreModel.init();
  Global.infoModel.addInfoWidget(
      "GitIgnore",
      ChangeNotifierProvider.value(
          value: gitIgnoreModel,
          builder: (context, child) => GitIgnoreCard()),
      title: "GitIgnore Generator");
}

Future<void> _update() async {
  gitIgnoreModel.refresh();
}

enum GitIgnoreCategory {
  languages,
  frameworks,
  editors,
  operatingSystems,
  other,
}

class GitIgnoreTemplate {
  final String name;
  final GitIgnoreCategory category;
  final String content;

  const GitIgnoreTemplate({
    required this.name,
    required this.category,
    required this.content,
  });
}

