String getGitIgnoreCategoryName(GitIgnoreCategory category) {
  switch (category) {
    case GitIgnoreCategory.languages:
      return 'Languages';
    case GitIgnoreCategory.frameworks:
      return 'Frameworks';
    case GitIgnoreCategory.editors:
      return 'Editors/IDEs';
    case GitIgnoreCategory.operatingSystems:
      return 'Operating Systems';
    case GitIgnoreCategory.other:
      return 'Other';
  }
}

Color getGitIgnoreCategoryColor(GitIgnoreCategory category, ColorScheme colorScheme) {
  switch (category) {
    case GitIgnoreCategory.languages:
      return colorScheme.primary;
    case GitIgnoreCategory.frameworks:
      return colorScheme.secondary;
    case GitIgnoreCategory.editors:
      return colorScheme.tertiary;
    case GitIgnoreCategory.operatingSystems:
      return colorScheme.primaryContainer;
    case GitIgnoreCategory.other:
      return colorScheme.surfaceContainerHighest;
  }
}

class GitIgnoreModel extends ChangeNotifier {
  bool _initialized = false;
  String _searchQuery = '';
  GitIgnoreCategory? _selectedCategory;
  final Set<String> _selectedTemplates = {};

  bool get initialized => _initialized;
  String get searchQuery => _searchQuery;
  GitIgnoreCategory? get selectedCategory => _selectedCategory;
  Set<String> get selectedTemplates => _selectedTemplates;
  List<GitIgnoreTemplate> get allTemplates => gitIgnoreTemplates;

  List<GitIgnoreTemplate> get filteredTemplates {
    var templates = gitIgnoreTemplates;

    if (_selectedCategory != null) {
      templates = templates.where((t) => t.category == _selectedCategory).toList();
    }

    if (_searchQuery.isNotEmpty) {
      final query = _searchQuery.toLowerCase();
      templates = templates.where((t) =>
        t.name.toLowerCase().contains(query) ||
        t.content.toLowerCase().contains(query)
      ).toList();
    }

    return templates;
  }

  String get generatedGitIgnore {
    if (_selectedTemplates.isEmpty) {
      return '# Select templates to generate .gitignore';
    }

    final selected = gitIgnoreTemplates.where((t) => _selectedTemplates.contains(t.name)).toList();
    final buffer = StringBuffer();

    buffer.writeln('# .gitignore generated by Flutter Launcher');
    buffer.writeln('# Combined templates: ${selected.map((t) => t.name).join(', ')}');
    buffer.writeln('');

    for (final template in selected) {
      buffer.writeln('# ===== ${template.name} =====');
      buffer.writeln(template.content);
      buffer.writeln('');
    }

    return buffer.toString();
  }

  void init() {
    if (!_initialized) {
      _initialized = true;
      Global.loggerModel.info("GitIgnore initialized", source: "GitIgnore");
      notifyListeners();
    }
  }

  void refresh() {
    notifyListeners();
  }

  void setSearchQuery(String query) {
    _searchQuery = query;
    notifyListeners();
  }

  void setSelectedCategory(GitIgnoreCategory? category) {
    _selectedCategory = category;
    notifyListeners();
  }

  void toggleTemplate(String name) {
    if (_selectedTemplates.contains(name)) {
      _selectedTemplates.remove(name);
    } else {
      _selectedTemplates.add(name);
    }
    notifyListeners();
    Global.loggerModel.info("GitIgnore template toggled: $name", source: "GitIgnore");
  }

  void clearAllTemplates() {
    _selectedTemplates.clear();
    notifyListeners();
  }

  void copyToClipboard(String text, BuildContext context) {
    Clipboard.setData(ClipboardData(text: text));
    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Text("Copied to clipboard"),
        duration: Duration(seconds: 2),
      ),
    );
  }
}

class GitIgnoreCard extends StatefulWidget {
  @override
  State<GitIgnoreCard> createState() => _GitIgnoreCardState();
}

class _GitIgnoreCardState extends State<GitIgnoreCard> {
  final TextEditingController _searchController = TextEditingController();

  @override
  void dispose() {
    _searchController.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final model = context.watch<GitIgnoreModel>();

    if (!model.initialized) {
      return Card.filled(
        color: Theme.of(context).cardColor,
        child: Padding(
          padding: EdgeInsets.all(16),
          child: CircularProgressIndicator(),
        ),
      );
    }

    return Card.filled(
      color: Theme.of(context).cardColor,
      child: Padding(
        padding: EdgeInsets.all(16),
        child: SingleChildScrollView(
          child: Column(
            mainAxisSize: MainAxisSize.min,
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Row(
                children: [
                  Icon(Icons.code, color: Theme.of(context).colorScheme.primary),
                  SizedBox(width: 8),
                  Text('GitIgnore Generator', style: Theme.of(context).textTheme.titleMedium),
                ],
              ),
              SizedBox(height: 12),
              _buildSearchField(context, model),
              SizedBox(height: 8),
              _buildCategoryFilter(context, model),
              SizedBox(height: 12),
              _buildTemplateSelection(context, model),
              if (model.selectedTemplates.isNotEmpty) ...[
                SizedBox(height: 12),
                _buildGeneratedOutput(context, model),
              ],
            ],
          ),
        ),
      ),
    );
  }

  Widget _buildSearchField(BuildContext context, GitIgnoreModel model) {
    return TextField(
      controller: _searchController,
      decoration: InputDecoration(
        hintText: 'Search templates',
        prefixIcon: Icon(Icons.search, size: 20),
        suffixIcon: _searchController.text.isNotEmpty
          ? IconButton(
              icon: Icon(Icons.clear, size: 18),
              onPressed: () {
                _searchController.clear();
                model.setSearchQuery('');
              },
            )
          : null,
        isDense: true,
        contentPadding: EdgeInsets.symmetric(horizontal: 12, vertical: 12),
        border: OutlineInputBorder(),
      ),
      onChanged: (value) => model.setSearchQuery(value),
    );
  }

  Widget _buildCategoryFilter(BuildContext context, GitIgnoreModel model) {
    return SingleChildScrollView(
      scrollDirection: Axis.horizontal,
      child: Row(
        children: [
          ActionChip(
            label: Text('All'),
            onPressed: () => model.setSelectedCategory(null),
            backgroundColor: model.selectedCategory == null
              ? Theme.of(context).colorScheme.primaryContainer
              : null,
          ),
          SizedBox(width: 4),
          ...GitIgnoreCategory.values.map((category) => Padding(
            padding: EdgeInsets.only(left: 4),
            child: ActionChip(
              label: Text(getGitIgnoreCategoryName(category)),
              onPressed: () => model.setSelectedCategory(category),
              backgroundColor: model.selectedCategory == category
                ? Theme.of(context).colorScheme.primaryContainer
                : null,
            ),
          )),
        ],
      ),
    );
  }

  Widget _buildTemplateSelection(BuildContext context, GitIgnoreModel model) {
    final templates = model.filteredTemplates;

    if (templates.isEmpty) {
      return Padding(
        padding: EdgeInsets.all(16),
        child: Text('No templates found', style: TextStyle(color: Theme.of(context).colorScheme.onSurfaceVariant)),
      );
    }

    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Row(
          mainAxisAlignment: MainAxisAlignment.spaceBetween,
          children: [
            Text('Templates (${model.selectedTemplates.length} selected)', style: TextStyle(fontWeight: FontWeight.w500)),
            if (model.selectedTemplates.isNotEmpty)
              TextButton(
                onPressed: () => model.clearAllTemplates(),
                child: Text('Clear All'),
              ),
          ],
        ),
        SizedBox(height: 8),
        Wrap(
          spacing: 8,
          runSpacing: 8,
          children: templates.take(20).map((template) => FilterChip(
            label: Text(template.name),
            selected: model.selectedTemplates.contains(template.name),
            onSelected: (selected) => model.toggleTemplate(template.name),
            avatar: Icon(_getCategoryIcon(template.category), size: 16),
          )).toList(),
        ),
      ],
    );
  }

  Widget _buildGeneratedOutput(BuildContext context, GitIgnoreModel model) {
    final output = model.generatedGitIgnore;
    final colorScheme = Theme.of(context).colorScheme;

    return Card(
      color: colorScheme.surfaceContainerHighest,
      elevation: 0,
      child: Padding(
        padding: EdgeInsets.all(12),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Row(
              mainAxisAlignment: MainAxisAlignment.spaceBetween,
              children: [
                Text('Generated .gitignore', style: TextStyle(fontWeight: FontWeight.bold)),
                Row(
                  children: [
                    IconButton(
                      icon: Icon(Icons.copy, size: 18),
                      onPressed: () => model.copyToClipboard(output, context),
                      tooltip: 'Copy to clipboard',
                    ),
                    IconButton(
                      icon: Icon(Icons.clear_all, size: 18),
                      onPressed: () => model.clearAllTemplates(),
                      tooltip: 'Clear selection',
                    ),
                  ],
                ),
              ],
            ),
            SizedBox(height: 8),
            Container(
              constraints: BoxConstraints(maxHeight: 200),
              child: SingleChildScrollView(
                child: SelectableText(
                  output,
                  style: TextStyle(fontSize: 12, fontFamily: 'monospace'),
                ),
              ),
            ),
          ],
        ),
      ),
    );
  }

  IconData _getCategoryIcon(GitIgnoreCategory category) {
    switch (category) {
      case GitIgnoreCategory.languages:
        return Icons.code;
      case GitIgnoreCategory.frameworks:
        return Icons.widgets;
      case GitIgnoreCategory.editors:
        return Icons.edit;
      case GitIgnoreCategory.operatingSystems:
        return Icons.computer;
      case GitIgnoreCategory.other:
        return Icons.folder;
    }
  }
}